SET NOCOUNT ON;

IF OBJECT_ID('workflow_template_categories', 'U') IS NULL
  CREATE TABLE workflow_template_categories (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, category_name NVARCHAR(180) NOT NULL, description NVARCHAR(500) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('workflow_templates', 'U') IS NULL
  CREATE TABLE workflow_templates (
    id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, template_code NVARCHAR(120) NOT NULL, template_name NVARCHAR(220) NOT NULL,
    description NVARCHAR(1000) NULL, category_id UNIQUEIDENTIFIER NULL, status NVARCHAR(80) NOT NULL DEFAULT 'Draft', validation_status NVARCHAR(80) NOT NULL DEFAULT 'not_validated',
    scope NVARCHAR(80) NOT NULL DEFAULT 'system', current_version INT NOT NULL DEFAULT 1, published_version INT NULL, complexity NVARCHAR(80) NOT NULL DEFAULT 'medium',
    estimated_duration_ms INT NOT NULL DEFAULT 0, estimated_cost DECIMAL(18,4) NOT NULL DEFAULT 0, stage_count INT NOT NULL DEFAULT 0, ai_agent_count INT NOT NULL DEFAULT 0,
    approval_required BIT NOT NULL DEFAULT 1, approval_configured BIT NOT NULL DEFAULT 1, recovery_enabled BIT NOT NULL DEFAULT 1, publishing_configured BIT NOT NULL DEFAULT 1,
    analytics_configured BIT NOT NULL DEFAULT 1, learning_configured BIT NOT NULL DEFAULT 1, final_output_ready BIT NOT NULL DEFAULT 1, recommended BIT NOT NULL DEFAULT 0,
    usage_count INT NOT NULL DEFAULT 0, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, recovery_coverage DECIMAL(8,2) NOT NULL DEFAULT 0, final_output_readiness DECIMAL(8,2) NOT NULL DEFAULT 0,
    owner_id NVARCHAR(180) NULL, owner_name NVARCHAR(180) NULL, organization_scope NVARCHAR(180) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), updated_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME()
  );
ELSE
BEGIN
  IF COL_LENGTH('workflow_templates','organization_id') IS NULL ALTER TABLE workflow_templates ADD organization_id UNIQUEIDENTIFIER NULL;
  IF COL_LENGTH('workflow_templates','template_code') IS NULL ALTER TABLE workflow_templates ADD template_code NVARCHAR(120) NULL;
  IF COL_LENGTH('workflow_templates','template_name') IS NULL ALTER TABLE workflow_templates ADD template_name NVARCHAR(220) NULL;
  IF COL_LENGTH('workflow_templates','description') IS NULL ALTER TABLE workflow_templates ADD description NVARCHAR(1000) NULL;
  IF COL_LENGTH('workflow_templates','category_id') IS NULL ALTER TABLE workflow_templates ADD category_id UNIQUEIDENTIFIER NULL;
  IF COL_LENGTH('workflow_templates','category') IS NULL ALTER TABLE workflow_templates ADD category NVARCHAR(180) NOT NULL CONSTRAINT df_workflow_templates_category DEFAULT 'General';
  IF COL_LENGTH('workflow_templates','status') IS NULL ALTER TABLE workflow_templates ADD status NVARCHAR(80) NOT NULL CONSTRAINT df_workflow_templates_status DEFAULT 'Draft';
  IF COL_LENGTH('workflow_templates','validation_status') IS NULL ALTER TABLE workflow_templates ADD validation_status NVARCHAR(80) NOT NULL CONSTRAINT df_workflow_templates_validation DEFAULT 'not_validated';
  IF COL_LENGTH('workflow_templates','scope') IS NULL ALTER TABLE workflow_templates ADD scope NVARCHAR(80) NOT NULL CONSTRAINT df_workflow_templates_scope DEFAULT 'system';
  IF COL_LENGTH('workflow_templates','current_version') IS NULL ALTER TABLE workflow_templates ADD current_version INT NOT NULL CONSTRAINT df_workflow_templates_current_version DEFAULT 1;
  IF COL_LENGTH('workflow_templates','published_version') IS NULL ALTER TABLE workflow_templates ADD published_version INT NULL;
  IF COL_LENGTH('workflow_templates','complexity') IS NULL ALTER TABLE workflow_templates ADD complexity NVARCHAR(80) NOT NULL CONSTRAINT df_workflow_templates_complexity DEFAULT 'medium';
  IF COL_LENGTH('workflow_templates','estimated_duration_ms') IS NULL ALTER TABLE workflow_templates ADD estimated_duration_ms INT NOT NULL CONSTRAINT df_workflow_templates_duration DEFAULT 0;
  IF COL_LENGTH('workflow_templates','estimated_cost') IS NULL ALTER TABLE workflow_templates ADD estimated_cost DECIMAL(18,4) NOT NULL CONSTRAINT df_workflow_templates_cost DEFAULT 0;
  IF COL_LENGTH('workflow_templates','stage_count') IS NULL ALTER TABLE workflow_templates ADD stage_count INT NOT NULL CONSTRAINT df_workflow_templates_stage_count DEFAULT 0;
  IF COL_LENGTH('workflow_templates','ai_agent_count') IS NULL ALTER TABLE workflow_templates ADD ai_agent_count INT NOT NULL CONSTRAINT df_workflow_templates_agent_count DEFAULT 0;
  IF COL_LENGTH('workflow_templates','approval_required') IS NULL ALTER TABLE workflow_templates ADD approval_required BIT NOT NULL CONSTRAINT df_workflow_templates_approval_required DEFAULT 1;
  IF COL_LENGTH('workflow_templates','approval_configured') IS NULL ALTER TABLE workflow_templates ADD approval_configured BIT NOT NULL CONSTRAINT df_workflow_templates_approval DEFAULT 1;
  IF COL_LENGTH('workflow_templates','recovery_enabled') IS NULL ALTER TABLE workflow_templates ADD recovery_enabled BIT NOT NULL CONSTRAINT df_workflow_templates_recovery DEFAULT 1;
  IF COL_LENGTH('workflow_templates','publishing_configured') IS NULL ALTER TABLE workflow_templates ADD publishing_configured BIT NOT NULL CONSTRAINT df_workflow_templates_publishing DEFAULT 1;
  IF COL_LENGTH('workflow_templates','analytics_configured') IS NULL ALTER TABLE workflow_templates ADD analytics_configured BIT NOT NULL CONSTRAINT df_workflow_templates_analytics DEFAULT 1;
  IF COL_LENGTH('workflow_templates','learning_configured') IS NULL ALTER TABLE workflow_templates ADD learning_configured BIT NOT NULL CONSTRAINT df_workflow_templates_learning DEFAULT 1;
  IF COL_LENGTH('workflow_templates','final_output_ready') IS NULL ALTER TABLE workflow_templates ADD final_output_ready BIT NOT NULL CONSTRAINT df_workflow_templates_output_ready DEFAULT 1;
  IF COL_LENGTH('workflow_templates','recommended') IS NULL ALTER TABLE workflow_templates ADD recommended BIT NOT NULL CONSTRAINT df_workflow_templates_recommended DEFAULT 0;
  IF COL_LENGTH('workflow_templates','usage_count') IS NULL ALTER TABLE workflow_templates ADD usage_count INT NOT NULL CONSTRAINT df_workflow_templates_usage DEFAULT 0;
  IF COL_LENGTH('workflow_templates','success_rate') IS NULL ALTER TABLE workflow_templates ADD success_rate DECIMAL(8,2) NOT NULL CONSTRAINT df_workflow_templates_success DEFAULT 0;
  IF COL_LENGTH('workflow_templates','recovery_coverage') IS NULL ALTER TABLE workflow_templates ADD recovery_coverage DECIMAL(8,2) NOT NULL CONSTRAINT df_workflow_templates_recovery_coverage DEFAULT 0;
  IF COL_LENGTH('workflow_templates','final_output_readiness') IS NULL ALTER TABLE workflow_templates ADD final_output_readiness DECIMAL(8,2) NOT NULL CONSTRAINT df_workflow_templates_final_readiness DEFAULT 0;
  IF COL_LENGTH('workflow_templates','owner_id') IS NULL ALTER TABLE workflow_templates ADD owner_id NVARCHAR(180) NULL;
  IF COL_LENGTH('workflow_templates','owner_name') IS NULL ALTER TABLE workflow_templates ADD owner_name NVARCHAR(180) NULL;
  IF COL_LENGTH('workflow_templates','organization_scope') IS NULL ALTER TABLE workflow_templates ADD organization_scope NVARCHAR(180) NULL;
  IF COL_LENGTH('workflow_templates','created_at') IS NULL ALTER TABLE workflow_templates ADD created_at DATETIME2 NOT NULL CONSTRAINT df_workflow_templates_created DEFAULT SYSUTCDATETIME();
  IF COL_LENGTH('workflow_templates','updated_at') IS NULL ALTER TABLE workflow_templates ADD updated_at DATETIME2 NOT NULL CONSTRAINT df_workflow_templates_updated DEFAULT SYSUTCDATETIME();
  EXEC('UPDATE workflow_templates SET category = COALESCE(NULLIF(category, ''''), ''General''), template_code = COALESCE(template_code, CONCAT(''TPL-LEGACY-'', RIGHT(CONVERT(NVARCHAR(36), id), 6))), template_name = COALESCE(template_name, ''Legacy Workflow Template''), description = COALESCE(description, ''Legacy template upgraded for dashboard compatibility''), validation_status = COALESCE(NULLIF(validation_status, ''''), ''Valid''), owner_name = COALESCE(owner_name, ''Autonomous Template Engine''), organization_scope = COALESCE(organization_scope, ''AI Media Group'') WHERE template_code IS NULL OR template_name IS NULL OR category IS NULL');
END;
IF OBJECT_ID('workflow_template_versions', 'U') IS NULL
  CREATE TABLE workflow_template_versions (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, workflow_template_id UNIQUEIDENTIFIER NOT NULL, template_id UNIQUEIDENTIFIER NULL, version_number INT NOT NULL, status NVARCHAR(80) NOT NULL, template_json NVARCHAR(MAX) NOT NULL DEFAULT '{}', created_by NVARCHAR(180) NULL, change_summary NVARCHAR(500) NULL, validation_status NVARCHAR(80) NULL, approval_status NVARCHAR(80) NULL, published_environments NVARCHAR(240) NULL, instantiation_count INT NOT NULL DEFAULT 0, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, rollback_eligible BIT NOT NULL DEFAULT 1, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
ELSE
BEGIN
  IF COL_LENGTH('workflow_template_versions','workflow_template_id') IS NULL ALTER TABLE workflow_template_versions ADD workflow_template_id UNIQUEIDENTIFIER NULL;
  IF COL_LENGTH('workflow_template_versions','template_id') IS NULL ALTER TABLE workflow_template_versions ADD template_id UNIQUEIDENTIFIER NULL;
  IF COL_LENGTH('workflow_template_versions','version_number') IS NULL ALTER TABLE workflow_template_versions ADD version_number INT NOT NULL CONSTRAINT df_workflow_template_versions_number DEFAULT 1;
  IF COL_LENGTH('workflow_template_versions','status') IS NULL ALTER TABLE workflow_template_versions ADD status NVARCHAR(80) NOT NULL CONSTRAINT df_workflow_template_versions_status DEFAULT 'Draft';
  IF COL_LENGTH('workflow_template_versions','template_json') IS NULL ALTER TABLE workflow_template_versions ADD template_json NVARCHAR(MAX) NOT NULL CONSTRAINT df_workflow_template_versions_json DEFAULT '{}';
  IF COL_LENGTH('workflow_template_versions','created_by') IS NULL ALTER TABLE workflow_template_versions ADD created_by NVARCHAR(180) NULL;
  IF COL_LENGTH('workflow_template_versions','change_summary') IS NULL ALTER TABLE workflow_template_versions ADD change_summary NVARCHAR(500) NULL;
  IF COL_LENGTH('workflow_template_versions','validation_status') IS NULL ALTER TABLE workflow_template_versions ADD validation_status NVARCHAR(80) NULL;
  IF COL_LENGTH('workflow_template_versions','approval_status') IS NULL ALTER TABLE workflow_template_versions ADD approval_status NVARCHAR(80) NULL;
  IF COL_LENGTH('workflow_template_versions','published_environments') IS NULL ALTER TABLE workflow_template_versions ADD published_environments NVARCHAR(240) NULL;
  IF COL_LENGTH('workflow_template_versions','instantiation_count') IS NULL ALTER TABLE workflow_template_versions ADD instantiation_count INT NOT NULL CONSTRAINT df_workflow_template_versions_instantiations DEFAULT 0;
  IF COL_LENGTH('workflow_template_versions','success_rate') IS NULL ALTER TABLE workflow_template_versions ADD success_rate DECIMAL(8,2) NOT NULL CONSTRAINT df_workflow_template_versions_success DEFAULT 0;
  IF COL_LENGTH('workflow_template_versions','rollback_eligible') IS NULL ALTER TABLE workflow_template_versions ADD rollback_eligible BIT NOT NULL CONSTRAINT df_workflow_template_versions_rollback DEFAULT 1;
  IF COL_LENGTH('workflow_template_versions','created_at') IS NULL ALTER TABLE workflow_template_versions ADD created_at DATETIME2 NOT NULL CONSTRAINT df_workflow_template_versions_created DEFAULT SYSUTCDATETIME();
END;
