  CREATE TABLE workflow_template_validation_results (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, workflow_template_validation_run_id UNIQUEIDENTIFIER NOT NULL, result_type NVARCHAR(80) NOT NULL, area NVARCHAR(120) NOT NULL, affected_stage NVARCHAR(120) NULL, message NVARCHAR(500) NOT NULL, suggested_fix NVARCHAR(500) NULL, auto_fix_available BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
