  CREATE TABLE workflow_template_performance (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, workflow_template_id UNIQUEIDENTIFIER NOT NULL, metric_date DATE NOT NULL DEFAULT CAST(SYSUTCDATETIME() AS DATE), instantiations INT NOT NULL DEFAULT 0, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, failure_rate DECIMAL(8,2) NOT NULL DEFAULT 0, recovery_rate DECIMAL(8,2) NOT NULL DEFAULT 0, average_duration_ms INT NOT NULL DEFAULT 0, average_cost DECIMAL(18,4) NOT NULL DEFAULT 0, approval_delay_ms INT NOT NULL DEFAULT 0, publishing_completion DECIMAL(8,2) NOT NULL DEFAULT 0, analytics_completion DECIMAL(8,2) NOT NULL DEFAULT 0, learning_completion DECIMAL(8,2) NOT NULL DEFAULT 0, final_output_rate DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
