  CREATE TABLE workflow_template_recommendations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, workflow_template_id UNIQUEIDENTIFIER NOT NULL, recommendation_type NVARCHAR(120) NOT NULL, title NVARCHAR(220) NOT NULL, recommendation NVARCHAR(500) NOT NULL, match_score DECIMAL(8,2) NULL, estimated_success_rate DECIMAL(8,2) NULL, estimated_duration_ms INT NULL, estimated_cost DECIMAL(18,4) NULL, required_configuration NVARCHAR(500) NULL, risk NVARCHAR(160) NULL, inside_guardrails BIT NOT NULL DEFAULT 1, status NVARCHAR(80) NOT NULL DEFAULT 'open', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
