  CREATE TABLE workflow_template_final_output_links (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, workflow_template_id UNIQUEIDENTIFIER NOT NULL, trigger_linked BIT NOT NULL DEFAULT 1, stages_linked BIT NOT NULL DEFAULT 1, agents_linked BIT NOT NULL DEFAULT 1, outputs_linked BIT NOT NULL DEFAULT 1, approval_linked BIT NOT NULL DEFAULT 1, publishing_linked BIT NOT NULL DEFAULT 1, analytics_linked BIT NOT NULL DEFAULT 1, learning_linked BIT NOT NULL DEFAULT 1, business_result_linked BIT NOT NULL DEFAULT 1, readiness_percent DECIMAL(8,2) NOT NULL DEFAULT 0, risk NVARCHAR(80) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());

IF OBJECT_ID('vw_workflow_templates_list', 'V') IS NOT NULL DROP VIEW vw_workflow_templates_list;
EXEC('CREATE VIEW vw_workflow_templates_list AS SELECT t.*, COALESCE(c.category_name,''Uncategorized'') AS category_name FROM workflow_templates t LEFT JOIN workflow_template_categories c ON c.id=t.category_id');
IF OBJECT_ID('vw_workflow_template_health', 'V') IS NOT NULL DROP VIEW vw_workflow_template_health;
EXEC('CREATE VIEW vw_workflow_template_health AS SELECT COALESCE(organization_id, CAST(0x0 AS UNIQUEIDENTIFIER)) AS organization_key, COUNT(*) AS total_templates, COUNT(CASE WHEN status IN (''Approved'',''Published'',''Production Ready'') THEN 1 END) AS approved_templates, COUNT(CASE WHEN status=''Production Ready'' THEN 1 END) AS production_ready, COUNT(CASE WHEN status=''Draft'' THEN 1 END) AS draft_templates, COUNT(CASE WHEN validation_status=''Invalid'' THEN 1 END) AS invalid_templates, COUNT(CASE WHEN status=''Deprecated'' THEN 1 END) AS deprecated_templates, COUNT(CASE WHEN recovery_enabled=0 THEN 1 END) AS missing_recovery, COUNT(CASE WHEN approval_configured=0 THEN 1 END) AS missing_approval_logic, COUNT(CASE WHEN publishing_configured=0 THEN 1 END) AS missing_publishing, COUNT(CASE WHEN analytics_configured=0 THEN 1 END) AS missing_analytics, COUNT(CASE WHEN learning_configured=0 THEN 1 END) AS missing_learning, CAST(AVG(success_rate) AS DECIMAL(8,2)) AS average_success_rate, CAST(AVG(final_output_readiness) AS DECIMAL(8,2)) AS average_final_output_rate, CAST(AVG(CASE WHEN validation_status=''Valid'' THEN 96.0 WHEN validation_status=''Warning'' THEN 82.0 ELSE 58.0 END) AS DECIMAL(8,2)) AS average_validation_score, MAX(updated_at) AS last_validation_run, COUNT(CASE WHEN validation_status IN (''Invalid'',''Warning'') THEN 1 END) AS human_attention_required FROM workflow_templates GROUP BY COALESCE(organization_id, CAST(0x0 AS UNIQUEIDENTIFIER))');
IF OBJECT_ID('vw_workflow_template_categories', 'V') IS NOT NULL DROP VIEW vw_workflow_template_categories;
EXEC('CREATE VIEW vw_workflow_template_categories AS SELECT c.id, c.organization_id, c.category_name, COUNT(t.id) AS template_count, COUNT(CASE WHEN t.status IN (''Approved'',''Production Ready'',''Published'') THEN 1 END) AS approved, COUNT(CASE WHEN t.status=''Draft'' THEN 1 END) AS draft, COUNT(CASE WHEN t.validation_status=''Invalid'' THEN 1 END) AS invalid, SUM(COALESCE(t.usage_count,0)) AS instantiations, CAST(AVG(COALESCE(t.success_rate,0)) AS DECIMAL(8,2)) AS success_rate, CAST(AVG(COALESCE(t.estimated_duration_ms,0)) AS INT) AS average_duration_ms, CAST(AVG(COALESCE(t.recovery_coverage,0)) AS DECIMAL(8,2)) AS recovery_coverage, CAST(AVG(COALESCE(t.final_output_readiness,0)) AS DECIMAL(8,2)) AS final_output_readiness, MAX(t.updated_at) AS last_updated, CAST(AVG(CASE WHEN t.validation_status=''Valid'' THEN 96.0 WHEN t.validation_status=''Warning'' THEN 82.0 ELSE 55.0 END) AS DECIMAL(8,2)) AS health_percent FROM workflow_template_categories c LEFT JOIN workflow_templates t ON t.category_id=c.id GROUP BY c.id, c.organization_id, c.category_name');
IF OBJECT_ID('vw_workflow_template_performance', 'V') IS NOT NULL DROP VIEW vw_workflow_template_performance;
EXEC('CREATE VIEW vw_workflow_template_performance AS SELECT p.*, t.template_code, t.template_name, t.organization_id, t.category_id FROM workflow_template_performance p JOIN workflow_templates t ON t.id=p.workflow_template_id');
IF OBJECT_ID('vw_workflow_template_dependencies', 'V') IS NOT NULL DROP VIEW vw_workflow_template_dependencies;
EXEC('CREATE VIEW vw_workflow_template_dependencies AS SELECT d.*, t.template_code, t.template_name, t.organization_id FROM workflow_template_dependencies d JOIN workflow_templates t ON t.id=d.workflow_template_id');
IF OBJECT_ID('vw_workflow_template_recommendations', 'V') IS NOT NULL DROP VIEW vw_workflow_template_recommendations;
EXEC('CREATE VIEW vw_workflow_template_recommendations AS SELECT r.*, t.template_code, t.template_name, t.organization_id, t.final_output_readiness, t.recovery_coverage FROM workflow_template_recommendations r JOIN workflow_templates t ON t.id=r.workflow_template_id');
IF OBJECT_ID('vw_workflow_template_final_output_readiness', 'V') IS NOT NULL DROP VIEW vw_workflow_template_final_output_readiness;
EXEC('CREATE VIEW vw_workflow_template_final_output_readiness AS SELECT l.*, t.template_code, t.template_name, t.organization_id, t.category_id FROM workflow_template_final_output_links l JOIN workflow_templates t ON t.id=l.workflow_template_id');
